import React from 'react';

const GlicoLogo = ({ size = 'medium', className = '' }) => {
  const sizeClasses = {
    small: 'h-8',
    medium: 'h-12',
    large: 'h-16'
  };

  const textSizes = {
    small: 'text-lg',
    medium: 'text-xl',
    large: 'text-2xl'
  };

  const lifeSizes = {
    small: 'text-xs',
    medium: 'text-sm',
    large: 'text-base'
  };

  return (
    <div className={`flex items-center ${sizeClasses[size]} ${className}`}>
      {/* Four Diagonal Stripes */}
      <div className="flex mr-3">
        <div className="w-1 h-full bg-red-500 transform rotate-12 mr-1"></div>
        <div className="w-1 h-full bg-cyan-400 transform rotate-12 mr-1"></div>
        <div className="w-1 h-full bg-blue-700 transform rotate-12 mr-1"></div>
        <div className="w-1 h-full bg-red-500 transform rotate-12"></div>
      </div>

      {/* GLICO Text */}
      <div className="flex flex-col">
        <div className={`text-red-500 font-bold tracking-wide ${textSizes[size]} flex`}>
          {/* Letter G with angular cut-out */}
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5" style={{ clipPath: 'polygon(0 0, 100% 0, 100% 100%, 20% 100%, 0 80%)' }}>G</span>

          {/* Letter L */}
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5">L</span>

          {/* Letter I */}
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5">I</span>

          {/* Letter C with square cut-out */}
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5" style={{ clipPath: 'polygon(0 0, 80% 0, 80% 100%, 0 100%)' }}>C</span>

          {/* Letter O as red square with white square cut-out */}
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-1 relative">
            <div className="w-full h-full bg-red-500 relative">
              <div className="absolute inset-1 bg-white"></div>
            </div>
            <span className="absolute -top-1 -right-1 text-xs text-black">®</span>
          </span>
        </div>

        {/* LIFE Text */}
        <div className={`text-blue-700 font-bold ${lifeSizes[size]} ml-1`}>
          LIFE
        </div>
      </div>
    </div>
  );
};

export default GlicoLogo;
